using System.Net;
using Microsoft.AspNetCore.HttpOverrides;

var builder = WebApplication.CreateBuilder(args);

// FIX 4 (ValidateScopes): .NET 9 enables ValidateScopes in development by
// default. A scoped IUserService captured by a singleton factory would throw
// InvalidOperationException at startup. Changed to AddScoped to match lifetimes.
builder.Services.AddScoped<IUserService, UserService>();
builder.Services.AddScoped<ICacheService>(sp =>
    new CacheService(sp.GetRequiredService<IUserService>()));

// FIX 1 (SocketsHttpHandler): .NET 9 HttpClientFactory uses SocketsHttpHandler
// by default. The previous cast to HttpClientHandler throws InvalidCastException.
builder.Services.AddHttpClient("api")
    .ConfigurePrimaryHttpMessageHandler(() => new SocketsHttpHandler { UseCookies = false });

// FIX 5 (Header redaction): .NET 9 redacts all header values in Trace-level
// HttpClientFactory logs. Allowlist non-sensitive headers you need for debugging.
builder.Services.ConfigureHttpClientDefaults(b =>
    b.RedactLoggedHeaders(h =>
        !string.Equals(h, "X-Forwarded-For", StringComparison.OrdinalIgnoreCase) &&
        !string.Equals(h, "X-Forwarded-Proto", StringComparison.OrdinalIgnoreCase) &&
        !string.Equals(h, "X-Forwarded-Host", StringComparison.OrdinalIgnoreCase)));

builder.Services.Configure<ForwardedHeadersOptions>(options =>
{
    options.ForwardedHeaders = ForwardedHeaders.XForwardedFor;
    // FIX 3 (ForwardedHeaders): .NET 9 ignores X-Forwarded-* headers from
    // proxies not in KnownProxies/KnownNetworks. Add your reverse proxy address.
    options.KnownProxies.Add(IPAddress.Loopback);
});

var app = builder.Build();
app.UseForwardedHeaders();
app.Run();

